// Validar firma HMAC-SHA256 del webhook de GHL (SEC-05)
const crypto = require('crypto');

const rawBody   = $input.first().binary?.data
  ? Buffer.from($input.first().binary.data, 'base64').toString('utf8')
  : JSON.stringify($input.first().json);

const sigHeader = $input.first().headers['x-ghl-signature'] || '';
const secret    = $env.WEBHOOK_SECRET;

if (!secret) throw new Error('WEBHOOK_SECRET no configurado');

if (!sigHeader) {
  $node['Respuesta 401'].json = { error: 'Firma ausente' };
  throw new Error('HMAC: header X-GHL-Signature ausente');
}

const receivedHex = sigHeader.startsWith('sha256=') ? sigHeader.slice(7) : sigHeader;
const receivedBuf = Buffer.from(receivedHex, 'hex');

const hmac = crypto.createHmac('sha256', secret);
hmac.update(rawBody);
const expectedBuf = Buffer.from(hmac.digest('hex'), 'hex');

if (receivedBuf.length !== expectedBuf.length || !crypto.timingSafeEqual(receivedBuf, expectedBuf)) {
  throw new Error('HMAC: firma invalida — rechazando webhook');
}

return $input.all();

// Sanitizar payload del contacto (SEC-06, ETL-08, ETL-09, ETL-10)
// Funciones copiadas de n8n/lib/sanitize.js

const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;
const REGEX_EMAIL       = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

function cleanStr(val, maxLen) {
  if (val === null || val === undefined) return null;
  const s = String(val).trim().substring(0, maxLen);
  return s.length > 0 ? s : null;
}

function normalizeE164(raw) {
  if (!raw) return null;
  let digits = String(raw).replace(/[^\d+]/g, '');
  if (digits.startsWith('+')) {
    const clean = '+' + digits.slice(1).replace(/\D/g, '');
    return (clean.length >= 8 && clean.length <= 16) ? clean : null;
  }
  if (/^3\d{9}$/.test(digits)) return '+57' + digits;
  if (/^57\d{10}$/.test(digits)) return '+' + digits;
  if (digits.length >= 7 && digits.length <= 15) return '+' + digits;
  return null;
}

function validateEmail(val) {
  if (!val) return null;
  const n = String(val).toLowerCase().trim().substring(0, 255);
  return REGEX_EMAIL.test(n) ? n : null;
}

function parseISODate(val) {
  if (!val) return null;
  const ts = Date.parse(String(val));
  return isNaN(ts) ? null : new Date(ts).toISOString();
}

const raw = $input.first().json;
const body = raw.body || raw;

const contact_id  = REGEX_GHL_ID.test(String(body.id || body.contactId || '').trim())
  ? String(body.id || body.contactId).trim() : null;
const _loc_raw = (raw.params && raw.params.location_id)
  ? raw.params.location_id
  : (body.locationId || '');
const location_id = REGEX_LOCATION_ID.test(String(_loc_raw).trim())
  ? String(_loc_raw).trim() : null;

if (!contact_id)  throw new Error('contact_id invalido: ' + (body.id || body.contactId));
if (!location_id) throw new Error('location_id invalido: ' + body.locationId);

const attrFirst = body.attributionSource || {};
const attrLast  = body.lastAttributionSource || {};

const clean = {
  contact_id,
  location_id,
  email:              validateEmail(body.email),
  phone:              normalizeE164(body.phone),
  first_name:         cleanStr(body.firstName  || body.first_name,  100),
  last_name:          cleanStr(body.lastName   || body.last_name,   100),
  source:             cleanStr(body.source, 100),
  tags:               Array.isArray(body.tags) ? body.tags.slice(0, 200).map(t => String(t).trim().substring(0, 200)) : null,
  contact_type:       cleanStr(body.contactType || body.type, 50),
  dnd:                body.dnd === true || body.dnd === 'true',
  custom_fields:      (body.customFields && typeof body.customFields === 'object') ? body.customFields : null,
  utm_source_first:   cleanStr(attrFirst.utmSource   || body.utm_source_first,   200),
  utm_medium_first:   cleanStr(attrFirst.utmMedium   || body.utm_medium_first,   200),
  utm_campaign_first: cleanStr(attrFirst.utmCampaign || body.utm_campaign_first, 200),
  utm_content_first:  cleanStr(attrFirst.utmContent  || body.utm_content_first,  200),
  utm_term_first:     cleanStr(attrFirst.utmTerm     || body.utm_term_first,     200),
  landing_url_first:  cleanStr(attrFirst.url         || body.landing_url_first,  2048),
  referrer_first:     cleanStr(attrFirst.referrer    || body.referrer_first,     2048),
  gclid_first:        cleanStr(attrFirst.gclid       || body.gclid_first,        200),
  fbclid_first:       cleanStr(attrFirst.fbclid      || body.fbclid_first,       200),
  campaign_id_first:  cleanStr(attrFirst.campaignId  || body.campaign_id_first,  100),
  utm_source_last:    cleanStr(attrLast.utmSource    || body.utm_source_last,    200),
  utm_medium_last:    cleanStr(attrLast.utmMedium    || body.utm_medium_last,    200),
  utm_campaign_last:  cleanStr(attrLast.utmCampaign  || body.utm_campaign_last,  200),
  utm_content_last:   cleanStr(attrLast.utmContent   || body.utm_content_last,   200),
  landing_url_last:   cleanStr(attrLast.url          || body.landing_url_last,   2048),
  ad_id_first:        cleanStr(attrFirst.adId        || body.ad_id_first,        100),
  ad_id_last:         cleanStr(attrLast.adId         || body.ad_id_last,         100),
  ctwa_clid_first:    cleanStr(attrFirst.ctwaClid    || body.ctwa_clid_first,    500),
  ctwa_clid_last:     cleanStr(attrLast.ctwaClid     || body.ctwa_clid_last,     500),
  ghl_created_at:     parseISODate(body.dateAdded    || body.createdAt),
  ghl_updated_at:     parseISODate(body.dateUpdated  || body.updatedAt),
  synced_at:          new Date().toISOString()
};

return [{ json: clean }];

// Aplicar logica SCD Tipo 2 para dim_contacts
// Referencia: GHL_Database.txt seccion 'Logica SCD Tipo 2'

const TRACKED = ['email', 'phone', 'source', 'utm_source_first', 'utm_campaign_first'];

const incoming = $('Sanitizar Contacto').first().json;
const existing = $input.first().json;  // resultado del SELECT previo

const now = new Date().toISOString();

// Si no hay fila existente → INSERT inicial
if (!existing || !existing.surrogate_key) {
  return [{
    json: {
      action: 'INSERT',
      record: Object.assign({}, incoming, {
        valid_from:    now,
        valid_to:      null,
        is_current:    true,
        change_reason: 'initial_insert'
      })
    }
  }];
}

// Detectar cambios en campos rastreados
const changedFields = TRACKED.filter(f => {
  const prevVal = existing[f] === undefined ? null : existing[f];
  const newVal  = incoming[f] === undefined ? null  : incoming[f];
  return String(prevVal) !== String(newVal);
});

if (changedFields.length > 0) {
  return [{
    json: {
      action:             'SCD_UPDATE',
      close_surrogate:    existing.surrogate_key,
      close_valid_to:     now,
      record:             Object.assign({}, incoming, {
        valid_from:    now,
        valid_to:      null,
        is_current:    true,
        change_reason: changedFields.map(f => f + '_change').join(', ')
      })
    }
  }];
}

// Sin cambios → actualizar minor
return [{
  json: {
    action:         'UPDATE_MINOR',
    surrogate_key:  existing.surrogate_key,
    synced_at:      now,
    ghl_updated_at: incoming.ghl_updated_at || now,
    tags:           incoming.tags,
    custom_fields:  incoming.custom_fields
  }
}];
